function getAllStates() {
  return states.map(({ id, name, capital, region, description, ancientName, age, tourismTagline, formation, language, statehoodDay, area, famousFor }) => ({
    id, name, capital, region, description, ancientName, age, tourismTagline, formation, language, statehoodDay, area, famousFor
  }));
}

function getStateDetail(id) {
  return states.find(s => s.id === id) || null;
}

function searchCulture(query) {
  const q = query.toLowerCase();
  const results = [];
  for (const state of states) {
    if (state.name.toLowerCase().includes(q) ||
        state.capital.toLowerCase().includes(q) ||
        state.ancientName?.toLowerCase().includes(q)) {
      results.push({ id: state.id, name: state.name, capital: state.capital, region: state.region, matchType: 'state' });
    }
    for (const city of state.famousCities) {
      if (city.name.toLowerCase().includes(q)) {
        results.push({ id: state.id, stateName: state.name, city: city, matchType: 'city' });
      }
    }
  }
  return results;
}

module.exports = { getAllStates, getStateDetail, searchCulture };
